/*
  Global design system derived from the hero design
  - Dark blue gradient canvas with subtle geometric pattern
  - Bold uppercase Space Grotesk headings, Source Sans 3 body
  - Flat buttons, 4px radius, strong blue accent
*/

:root {
  /* Brand colors */
  --color-primary-900: #0c2f57; /* header background */
  --color-primary-800: #103765;
  --color-primary-700: #1d4f8c; /* gradient end */

  --color-secondary-500: #2f80ff; /* primary CTA */
  --color-secondary-400: #6c8db5;

  --color-accent-cta-bg: #2f80ff;
  --color-accent-cta-text: #ffffff;
  --color-accent-cta-secondary-bg: #f1f5ff; /* light CTA in header */

  --color-neutral-100: #ffffff;
  --color-neutral-200: #e0e6f0;
  --color-neutral-300: #a8b4c6;
  --color-neutral-700: #6c8db5;
  --color-neutral-900: #051629;

  --color-success: #27ae60;
  --color-error: #e53935;
  --color-warning: #f2c94c;
  --color-info: #2f80ff;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 52px;
  --font-size-h2: 36px;
  --font-size-h3: 24px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --header-height: 72px;
  --footer-height-min: 80px;
  --border-radius-sm: 4px;
  --border-radius-md: 6px;
  --shadow-soft: 0 8px 24px rgba(0, 0, 0, 0.12);
}

/* Reset & base elements */

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  height: 100%;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-100);
  background:
    radial-gradient(circle at 0% 0%, #1d4f8c 0, #0c2f57 40%, #051629 100%);
  position: relative;
}

/* Geometric pattern overlay similar to hero */
body::before {
  content: '';
  position: fixed;
  inset: 0;
  background-image:
    linear-gradient(60deg, rgba(255, 255, 255, 0.04) 1px, transparent 1px),
    linear-gradient(120deg, rgba(255, 255, 255, 0.04) 1px, transparent 1px);
  background-size: 40px 40px;
  opacity: 0.25;
  pointer-events: none;
  z-index: -1;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: none;
}

ul {
  list-style: none;
  margin: 0;
  padding: 0;
}

/* Layout helpers */

.container {
  width: 100%;
  max-width: 1120px;
  margin: 0 auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

.site-main {
  min-height: calc(100vh - var(--header-height) - var(--footer-height-min));
  padding-top: var(--space-7);
  padding-bottom: var(--space-7);
}

/* Header & navigation */

.site-header {
  position: sticky;
  top: 0;
  z-index: 40;
  background-color: var(--color-primary-900);
  box-shadow: 0 2px 0 rgba(0, 0, 0, 0.2);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--header-height);
  gap: var(--space-4);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  color: var(--color-neutral-100);
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  font-size: 20px;
}

/* Hexagonal-ish mark built with pure CSS to echo the logo without SVG */
.brand-mark {
  position: relative;
  width: 28px;
  height: 28px;
  border-radius: 6px;
  background: linear-gradient(135deg, #2f80ff 0%, #6c8db5 50%, #f1f5ff 100%);
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.25);
}

.brand-mark::before,
.brand-mark::after {
  content: '';
  position: absolute;
  inset: 4px;
  border-radius: 4px;
  border: 2px solid rgba(12, 47, 87, 0.6);
}

.brand-mark::after {
  inset: 9px;
  border-color: rgba(12, 47, 87, 0.85);
}

.brand-text {
  white-space: nowrap;
}

.primary-nav {
  flex: 1 1 auto;
}

.nav-list {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-4);
  font-size: 15px;
}

.nav-item {
  position: relative;
}

.nav-link {
  display: inline-flex;
  align-items: center;
  padding: var(--space-1) 0;
  color: var(--color-neutral-100);
  font-weight: var(--font-weight-medium);
  opacity: 0.9;
}

.nav-link:hover,
.nav-link:focus {
  opacity: 1;
}

.nav-item::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: -10px;
  height: 2px;
  background-color: var(--color-secondary-500);
  transform: scaleX(0);
  transform-origin: center;
  transition: transform 0.18s ease-out;
}

.nav-item:hover::after,
.nav-item.is-active::after {
  transform: scaleX(1);
}

.nav-actions {
  flex: 0 0 auto;
}

/* Buttons */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--border-radius-sm);
  border: none;
  cursor: pointer;
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: var(--font-weight-semibold);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding: 12px 26px;
  transition: background-color 0.15s ease-out, color 0.15s ease-out, transform 0.1s ease-out;
  text-decoration: none;
}

.btn-primary {
  background-color: var(--color-accent-cta-bg);
  color: var(--color-accent-cta-text);
}

.btn-primary:hover,
.btn-primary:focus {
  background-color: #2268dd;
  transform: translateY(-1px);
}

.btn-secondary {
  background-color: var(--color-accent-cta-secondary-bg);
  color: var(--color-primary-900);
  padding: 10px 22px;
}

.btn-secondary:hover,
.btn-secondary:focus {
  background-color: #e0e9ff;
  transform: translateY(-1px);
}

/* Footer */

.site-footer {
  background-color: #061d35;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding-top: var(--space-5);
  padding-bottom: var(--space-5);
  color: var(--color-neutral-300);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
}

.footer-branding {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.footer-logo {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  color: var(--color-neutral-100);
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  font-size: 18px;
}

.footer-tagline {
  font-size: var(--font-size-small);
  color: var(--color-neutral-300);
}

.footer-nav {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
  font-size: var(--font-size-small);
}

.footer-link {
  color: var(--color-neutral-200);
}

.footer-link:hover,
.footer-link:focus {
  color: var(--color-secondary-500);
}

.footer-meta {
  flex-basis: 100%;
  margin-top: var(--space-2);
  font-size: 12px;
  color: var(--color-neutral-300);
}

/* Basic responsive adjustments without additional interactive controls */

@media (max-width: 960px) {
  .header-inner {
    flex-wrap: wrap;
    justify-content: flex-start;
    row-gap: var(--space-2);
  }

  .primary-nav {
    order: 2;
    width: 100%;
  }

  .nav-list {
    justify-content: flex-start;
    overflow-x: auto;
    padding-bottom: 4px;
  }

  .nav-actions {
    order: 3;
    width: 100%;
    display: flex;
    justify-content: flex-start;
    padding-bottom: var(--space-2);
  }

  .site-main {
    padding-top: var(--space-5);
    padding-bottom: var(--space-5);
  }
}

@media (max-width: 640px) {
  .brand-text {
    font-size: 18px;
  }

  .btn {
    font-size: 13px;
    padding-inline: 18px;
  }

  .footer-inner {
    align-items: flex-start;
  }
}
